def test_is_law_is():
    """ Making sure numeric values entered are 1-48  """
    assert is_law("5", all_laws) == {'number': '5', 'law': '5. So Much Depends on Reputation – Guard It with Your Life',
                                     'summary': 'Reputation is power; protect and shape it carefully.', 'figure': 'Cesare Borgia'}
    assert is_law("10000", all_laws) == False


def test_lawFork_is():
    ''' Checking the values to see if lowercase '''
    law = 1
    assert lawFork("SUMMARY", law) != "summary"
    assert lawFork("FIGURE", law) != "figure"
    assert lawFork("BOTH", law) != "both"


def test_random_law():
    """ Random mode ON """
    all_laws = [{'number': 22, 'law': '22. Use the Surrender Tactic: Transform Weakness into Power',
                 'summary': 'Yielding can be a strategic move.', 'figure': 'Napoleon Bonaparte'}]
    random.sample(range(48), k=1)
    assert random_law(all_laws) == {'number': 22, 'law': '22. Use the Surrender Tactic: Transform Weakness into Power',
                                    'summary': 'Yielding can be a strategic move.', 'figure': 'Napoleon Bonaparte'}
